    // Get product ID from URL
    // Only run this code on product.html
if(window.location.pathname.includes("product.html")){

const params = new URLSearchParams(window.location.search);
const productId = parseInt(params.get("id"));

const product = products.find(p => p.id === productId);

if(!product) {
  document.body.innerHTML = "<h2>Product not found</h2>";
} else {

const mainImage = document.getElementById("mainImage");
const thumbnailsDiv = document.getElementById("thumbnails");
const productTitle = document.getElementById("productTitle");
const productPrice = document.getElementById("productPrice");
const productDesc = document.getElementById("productDesc");
const productLongDesc = document.getElementById("productLongDesc");
const quantityInput = document.getElementById("quantity");

mainImage.src = product.images[0];
productTitle.textContent = product.title;
productPrice.textContent = product.price;
productDesc.textContent = product.description;
productLongDesc.textContent = product.longDescription;

let activeThumb = null;

product.images.forEach((src,index)=>{
const thumb = document.createElement("img");
thumb.src = src;

if(index === 0){
thumb.classList.add("active");
activeThumb = thumb;
}

thumb.onclick = ()=>{
mainImage.src = src;
if(activeThumb) activeThumb.classList.remove("active");
thumb.classList.add("active");
activeThumb = thumb;
};

thumbnailsDiv.appendChild(thumb);

});

document.getElementById("increaseQty").onclick = () => quantityInput.value = parseInt(quantityInput.value) + 1;

document.getElementById("decreaseQty").onclick = () => {
if(quantityInput.value > 1) quantityInput.value = parseInt(quantityInput.value) - 1;
};

// document.getElementById("addToCart").onclick = () => {
// alert(`Added ${quantityInput.value} x ${product.title} to cart`);
// };




// Inside your if(window.location.pathname.includes("product.html")) block:

document.getElementById("addToCart").onclick = () => {
    // 1. Get current cart from memory
    let cart = JSON.parse(localStorage.getItem("cart")) || [];

    // 2. Create the item using the 'product' object already defined in your code
    // We use product.images[0] because it's an array
    const newItem = {
        id: product.id,
        name: product.title,
        price: parseFloat(product.price.toString().replace(/[^0-9.]/g, '')),
        image: product.images[0],
        quantity: parseInt(document.getElementById("quantity").value)
    };

    // 3. Add to cart (check for duplicates)
    const existing = cart.find(item => item.id === newItem.id);
    if (existing) {
        existing.quantity += newItem.quantity;
    } else {
        cart.push(newItem);
    }

    // 4. Save to LocalStorage
    localStorage.setItem("cart", JSON.stringify(cart));

    // 5. Tell the sidebar to update and slide open
    renderCart(); 
    document.getElementById("cartSidebar").classList.add("active");
    document.getElementById("cartOverlay").classList.add("active");
};

}

}




































